import{_ as a,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Démarrage Rapide : Installation et Configuration d'Antigravity Auth | OpenCode","description":"Apprenez à installer et configurer le plugin Antigravity Auth. Effectuez l'authentification Google OAuth et envoyez votre première requête modèle en 10 minutes, en vérifiant l'accès aux modèles Claude et Gemini.","frontmatter":{"title":"Démarrage Rapide : Installation et Configuration d'Antigravity Auth | OpenCode","sidebarTitle":"Opérationnel en 10 Minutes","subtitle":"Démarrage Rapide : Installation et Configuration d'Antigravity Auth","description":"Apprenez à installer et configurer le plugin Antigravity Auth. Effectuez l'authentification Google OAuth et envoyez votre première requête modèle en 10 minutes, en vérifiant l'accès aux modèles Claude et Gemini.","order":1},"headers":[],"relativePath":"fr/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"fr/NoeFabris/opencode-antigravity-auth/start/index.md"}`),n={name:"fr/NoeFabris/opencode-antigravity-auth/start/index.md"};function o(l,e,s,u,d,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="demarrage-rapide" tabindex="-1">Démarrage Rapide <a class="header-anchor" href="#demarrage-rapide" aria-label="Permalink to &quot;Démarrage Rapide&quot;">​</a></h1><p>Ce chapitre vous guide depuis zéro jusqu&#39;à l&#39;utilisation du plugin Antigravity Auth. Vous découvrirez la valeur fondamentale du plugin, terminerez l&#39;installation et l&#39;authentification OAuth, et enverrez votre première requête modèle pour vérifier que la configuration fonctionne.</p><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;Apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;Apprentissage&quot;">​</a></h2><p>Suivez cet ordre d&#39;apprentissage, chaque étape s&#39;appuyant sur la précédente :</p><h3 id="_1-presentation-du-plugin" tabindex="-1">1. <a href="./what-is-antigravity-auth/">Présentation du Plugin</a> <a class="header-anchor" href="#_1-presentation-du-plugin" aria-label="Permalink to &quot;1. [Présentation du Plugin](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Découvrez la valeur fondamentale du plugin Antigravity Auth, ses cas d&#39;usage et les avertissements sur les risques.</p><ul><li>Déterminez si le plugin correspond à votre cas d&#39;usage</li><li>Découvrez les modèles IA pris en charge (Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash)</li><li>Comprenez clairement les risques et précautions d&#39;utilisation</li></ul><h3 id="_2-installation-rapide" tabindex="-1">2. <a href="./quick-install/">Installation Rapide</a> <a class="header-anchor" href="#_2-installation-rapide" aria-label="Permalink to &quot;2. [Installation Rapide](./quick-install/)&quot;">​</a></h3><p>Effectuez l&#39;installation du plugin et la première authentification en 5 minutes.</p><ul><li>Deux méthodes d&#39;installation (assistance IA / configuration manuelle)</li><li>Configuration des définitions de modèles</li><li>Exécution de l&#39;authentification Google OAuth</li></ul><h3 id="_3-authentification-oauth-2-0-pkce" tabindex="-1">3. <a href="./first-auth-login/">Authentification OAuth 2.0 PKCE</a> <a class="header-anchor" href="#_3-authentification-oauth-2-0-pkce" aria-label="Permalink to &quot;3. [Authentification OAuth 2.0 PKCE](./first-auth-login/)&quot;">​</a></h3><p>Comprenez le flux d&#39;authentification OAuth 2.0 PKCE et terminez votre première connexion.</p><ul><li>Comprenez le mécanisme de sécurité PKCE</li><li>Terminez votre première connexion pour obtenir les droits d&#39;accès API</li><li>Découvrez le traitement automatisé du rafraîchissement des tokens</li></ul><h3 id="_4-premiere-requete" tabindex="-1">4. <a href="./first-request/">Première Requête</a> <a class="header-anchor" href="#_4-premiere-requete" aria-label="Permalink to &quot;4. [Première Requête](./first-request/)&quot;">​</a></h3><p>Effectuez votre première requête modèle pour vérifier que l&#39;installation réussit.</p><ul><li>Envoyez votre première requête modèle Antigravity</li><li>Comprenez les paramètres <code>--model</code> et <code>--variant</code></li><li>Diagnostic des erreurs courantes de requêtes modèles</li></ul><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><p>Avant de commencer ce chapitre, assurez-vous que :</p><ul><li>✅ OpenCode CLI est installé (la commande <code>opencode</code> est disponible)</li><li>✅ Vous disposez d&#39;un compte Google (pour l&#39;authentification OAuth)</li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines Étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines Étapes&quot;">​</a></h2><p>Après avoir terminé le démarrage rapide, vous pouvez :</p><ul><li><strong><a href="./../platforms/available-models/">Découvrir les Modèles Disponibles</a></strong> — Explorez tous les modèles pris en charge et leurs configurations de variantes</li><li><strong><a href="./../advanced/multi-account-setup/">Configuration Multi-Comptes</a></strong> — Configurez plusieurs comptes Google pour le pool de quotas</li><li><strong><a href="./../faq/common-auth-issues/">Problèmes d&#39;Authentification Courants</a></strong> — Consultez le guide de dépannage en cas de problèmes</li></ul>',22)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
